public static byte[] encodeBase64(byte[] binaryData, boolean isChunked, boolean urlSafe, int maxResultSize) {
 if (binaryData == null) {
 return null;
 }

long len = binaryData.length * 4 / 3;
if (len > maxResultSize) {
 throw new IllegalArgumentException("Input array too big, the output array would be bigger (" + len + ") than the specified maxium size of " + maxResultSize);
 }

Base64 b64;
if (isChunked) {
 b64 = new Base64(urlSafe);
} else if (urlSafe) {
 b64 = new Base64(0, CHUNK_SEPARATOR, urlSafe);
}
else {
 b64 = new Base64(0);
}

return b64.encode(binaryData);
}
